                                    value={formData['Долг']} 
                                    onChange={handleInputChange}
                                    className="!bg-red-50/50 dark:!bg-red-900/20 !border-red-300 dark:!border-red-800 focus:!ring-red-500 text-red-800 dark:text-red-200 font-semibold"
                                />
