                <div className="flex justify-end">
                    <Button type="submit" size="lg" disabled={isLoading} className="w-full sm:w-auto">
                        {isLoading ? loadingMessage : originalClient ? 'Оформить новый заказ' : 'Оформить и уведомить'}
                    </Button>
                </div>
            </form>
        </div>
    );
};

