export const MultiTireInput: React.FC<MultiTireInputProps> = ({ groups, onGroupsChange }) => {
  const [currentValue, setCurrentValue] = useState('');
  const [currentSeason, setCurrentSeason] = useState<'Лето' | 'Зима'>('Лето');
  const [currentCount, setCurrentCount] = useState<number>(2);
  const [currentHasRims, setCurrentHasRims] = useState<'Да' | 'Нет'>('Нет');
  const [currentDot, setCurrentDot] = useState('');

  const [editingGroupId, setEditingGroupId] = useState<string | null>(null);

  // Helper to parse the composite string from SmartTireInput
  const parseValue = (val: string) => {
    const parts = val.split('>>');
    const brandAndModelPart = (parts[0] || '').trim();
    const sizePart = (parts[1] || '').trim();

    const firstSpaceIndex = brandAndModelPart.indexOf(' ');
    let brand = '', model = '';
    if (firstSpaceIndex > -1) {
        brand = brandAndModelPart.substring(0, firstSpaceIndex);
        model = brandAndModelPart.substring(firstSpaceIndex + 1);
    } else {
        brand = brandAndModelPart;
    }

    const sizeMatch = sizePart.match(/(\d+)\/?(\d*)[R]?(\d*)/);
    let width = '', profile = '', diameter = '';
    if (sizeMatch) {
      width = sizeMatch[1] || '';
      profile = sizeMatch[2] || '';
      diameter = sizeMatch[3] || '';
    }
    return { brand, model, width, profile, diameter };
  };

  const calculatePrice = (diameter: string) => {
      return PRICE_BY_DIAMETER[diameter] || DEFAULT_PRICE;
  };

  const handleSaveGroup = () => {
    const { brand, model, width, profile, diameter } = parseValue(currentValue);

    if (!diameter) return;

    const newGroup: TireGroup = {
        id: editingGroupId || `g-${Date.now()}`,
        brand: brand || 'Не указан',
        model: model || '',
        width,
        profile,
        diameter,
        count: currentCount,
        season: currentSeason,
        hasRims: currentHasRims,
        pricePerMonth: calculatePrice(diameter),
        dot: currentDot
    };

    if (editingGroupId) {
        onGroupsChange(groups.map(g => g.id === editingGroupId ? newGroup : g));
        setEditingGroupId(null);
    } else {
        onGroupsChange([...groups, newGroup]);
    }

    // Reset inputs
    setCurrentValue(''); 
    setCurrentCount(2); 
    setCurrentDot('');
    // We keep Season and Rims as they often repeat
  };

  const handleEditGroup = (group: TireGroup) => {
      setEditingGroupId(group.id);

      // Reconstruct value string for SmartTireInput
      const brandModel = `${group.brand} ${group.model}`.trim();
      const size = `${group.width}/${group.profile}R${group.diameter}`;
      setCurrentValue(`${brandModel} >> ${size}`);

      setCurrentSeason(group.season);
      setCurrentCount(group.count);
      setCurrentHasRims(group.hasRims);
      setCurrentDot(group.dot || '');
  };

  const handleRemoveGroup = (id: string, e: React.MouseEvent) => {
      e.stopPropagation(); // Prevent triggering edit
      if (editingGroupId === id) {
          setEditingGroupId(null);
          setCurrentValue('');
          setCurrentDot('');
      }
      onGroupsChange(groups.filter(g => g.id !== id));
  };

  const isInputValid = () => {
      const { diameter } = parseValue(currentValue);
      return !!diameter;
  };

  return (
    <div className="space-y-4">
        {/* List of Added Groups */}
        {groups.length > 0 && (
            <div className="space-y-2 mb-4">
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Состав комплекта (Нажмите для изменения)</label>
                {groups.map((group) => (
                    <div 
                        key={group.id} 
                        onClick={() => handleEditGroup(group)}
                        className={`
                            relative flex items-center justify-between p-3 border rounded-lg shadow-sm cursor-pointer transition-all
                            ${editingGroupId === group.id 
                                ? 'bg-primary-50 border-primary-500 ring-1 ring-primary-500 dark:bg-primary-900/30' 
                                : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 hover:border-gray-300 dark:hover:border-gray-600'
                            }
                        `}
                    >
                        <div className="flex-1">
                            <div className="flex items-center gap-2">
                                <span className="font-bold text-gray-900 dark:text-white">{group.count} шт</span>
                                <span className="text-gray-400">|</span>
                                <span className="font-semibold text-primary-600 dark:text-primary-400">{group.width}/{group.profile} R{group.diameter}</span>
                            </div>
                            <div className="text-sm text-gray-600 dark:text-gray-400">
                                {group.brand} {group.model} 
                                <span className="ml-2 text-xs bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded">
                                    {group.season}
                                </span>
                                {group.hasRims === 'Да' && <span className="ml-1 text-xs bg-blue-50 text-blue-600 px-1.5 py-0.5 rounded">Диски</span>}
                                {group.dot && <span className="ml-1 text-xs text-gray-500 font-mono">DOT: {group.dot}</span>}
                            </div>
                        </div>
                        <div className="flex items-center gap-1">
                            {editingGroupId === group.id && (
                                <span className="text-xs font-bold text-primary-600 mr-2 animate-pulse">Редактирование...</span>
                            )}
                            <button 
                                type="button" 
                                onClick={(e) => handleRemoveGroup(group.id, e)}
                                className="p-2 text-gray-400 hover:text-red-500 transition-colors z-10"
                            >
                                <TrashIcon />
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        )}

        {/* Input Area */}
        <div className={`transition-all duration-300 ${groups.length > 0 ? 'bg-gray-50 dark:bg-gray-800/30 p-4 rounded-xl border border-dashed border-gray-300 dark:border-gray-700' : ''}`}>
            <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700 dark:text-gray-300">
                    {editingGroupId ? "Редактирование группы" : (groups.length === 0 ? "Параметры шин" : "Добавить еще шины / другую ось")}
                </span>
                {editingGroupId && (
                    <button type="button" onClick={() => { setEditingGroupId(null); setCurrentValue(''); setCurrentDot(''); }} className="text-xs text-red-500 underline">
                        Отменить
                    </button>
                )}
            </div>

            <SmartTireInput
                label=""
                value={currentValue}
                onChange={setCurrentValue}
                season={currentSeason}
                onSeasonChange={setCurrentSeason}
                tireCount={currentCount}
                onTireCountChange={setCurrentCount}
                hasRims={currentHasRims}
                onHasRimsChange={setCurrentHasRims}
            />

            {/* Embedded DOT Input */}
            <div className="mt-3">
                <label className="block text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">DOT-код (для этой группы)</label>
                <input 
                    type="text"
                    value={currentDot}
                    onChange={(e) => setCurrentDot(e.target.value)}
                    placeholder="Например: 4523"
                    className="block w-full rounded-md border-gray-300 shadow-sm focus:border-primary-500 focus:ring-primary-500 py-2 px-3 dark:bg-gray-800 dark:border-gray-600 dark:text-white sm:text-sm"
                />
            </div>

            <div className="mt-4 flex justify-end">
                <Button 
                    type="button" 
                    variant={editingGroupId ? "primary" : "secondary"}
                    size="sm"
                    onClick={handleSaveGroup}
                    disabled={!isInputValid()}
                    className={!isInputValid() ? 'opacity-50 cursor-not-allowed' : ''}
                >
                    {editingGroupId ? <CheckIcon /> : <PlusIcon />} 
                    <span className="ml-1">
                        {editingGroupId ? "Сохранить изменения" : (groups.length === 0 ? "Добавить в заказ" : "Добавить группу")}
                    </span>
                </Button>
            </div>
        </div>
    </div>
  );
};

