                )}
                {activeTab === 'history' && <OrderHistory client={client} />}
                {activeTab === 'photos' && <PhotoGallery client={client} refreshClientData={refreshData} showToast={showToast} />}
            </div>
        )
    }

    const renderFooter = () => {
        if (mode === 'edit') {
            return (
                <>
                    <Button variant="outline" onClick={() => setMode('view')} disabled={isSubmitting}>Отмена</Button>
                    <Button onClick={handleSave} disabled={isSubmitting}>{isSubmitting ? 'Сохранение...' : 'Сохранить'}</Button>
                </>
            );
        }
        if (mode === 'message') {
            return (
                <>
                    <Button variant="outline" onClick={() => setMode('view')} disabled={isSubmitting}>Назад</Button>
                    <Button onClick={handleSendMessage} disabled={isSubmitting || templates.length === 0 || !client?.['Chat ID']}>{isSubmitting ? 'Отправка...' : 'Отправить'}</Button>
                </>
            );
        }
        return (
            <div className='flex flex-wrap gap-2 w-full justify-start'>
                <Button size="sm" variant="primary" onClick={() => setMode('edit')}><EditIcon/> <span className="ml-1">Изменить</span></Button>
                <Button size="sm" variant="secondary" onClick={handleNewOrder} className="!bg-green-100 !text-green-800 hover:!bg-green-200 dark:!bg-green-800/40 dark:!text-green-200 dark:hover:!bg-green-800/60"><DocumentPlusIcon className="h-4 w-4"/> <span className="ml-1">Новый заказ</span></Button>
                <Button size="sm" variant="secondary" onClick={() => setMode('message')}><MessageIcon/> <span className="ml-1">Сообщение</span></Button>
                <div className="flex-grow"></div>
                <Button size="sm" variant="danger" onClick={handleDelete} disabled={isSubmitting}><DeleteIcon/> <span className="ml-1">Удалить</span></Button>
            </div>
        )
    }

    const modalTitleNode = (
        <div className="flex flex-col">
            <span className="text-xl font-bold leading-tight">{formData?.['Имя клиента']}</span>
            <div className="flex flex-wrap items-center gap-2 mt-1">
                 {formData?.['Номер Авто'] && (
                    <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-800 dark:text-gray-200 font-mono">
                        {formData['Номер Авто']}
                    </span>
                 )}
                 {formData?.['Телефон'] && (
                    <span className="text-sm text-gray-500 dark:text-gray-400">
                        {formData['Телефон']}
                    </span>
                 )}
            </div>
        </div>
    );

    return (
        <Modal 
            isOpen={isOpen}
            onClose={onClose}
            title={modalTitleNode}
            footer={<div className="flex justify-end w-full space-x-2">{renderFooter()}</div>}
        >
            <div className="border-b border-gray-200 dark:border-gray-700 mb-4">
                <nav className="-mb-px flex space-x-4" aria-label="Tabs">
                    <TabButton active={activeTab === 'details'} onClick={() => setActiveTab('details')}>Детали</TabButton>
                    <TabButton active={activeTab === 'history'} onClick={() => setActiveTab('history')}>История заказов</TabButton>
                    <TabButton active={activeTab === 'photos'} onClick={() => setActiveTab('photos')}>Фото</TabButton>
                </nav>
            </div>
            {renderContent()}
        </Modal>
    );
};

interface ClientsViewProps {
  clients: Client[];
  headers: string[];
  templates: MessageTemplate[];
  refreshData: () => Promise<void>;
  savedViews: SavedView[];
  onSaveViews: (views: SavedView[]) => void;
}

export const ClientsView: React.FC<ClientsViewProps> = ({ clients, headers, templates, refreshData, savedViews, onSaveViews }) => {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortConfig, setSortConfig] = useState<{ key: string; direction: 'ascending' | 'descending' } | null>({ key: 'Дата добавления', direction: 'descending' });
    const [selectedClient, setSelectedClient] = useState<Client | null>(null);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedClientIds, setSelectedClientIds] = useState<Set<string>>(new Set());

    // Filters
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [debtFilter, setDebtFilter] = useState<boolean>(false);
    const [warehouseFilter, setWarehouseFilter] = useState<string>('');
    const [showFilters, setShowFilters] = useState(false);

    const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

    // Load URL params
    const [searchParams, setSearchParams] = useSearchParams();
    useEffect(() => {
        const q = searchParams.get('q');
        if (q) setSearchTerm(q);
        const debt = searchParams.get('debt');
        if (debt === 'true') setDebtFilter(true);
    }, [searchParams]);

    const showToast = (message: string, type: 'success' | 'error') => {
        setToast({ message, type });
    };

    const handleSort = (key: string) => {
        let direction: 'ascending' | 'descending' = 'ascending';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'ascending') {
            direction = 'descending';
        }
        setSortConfig({ key, direction });
    };

    const filteredClients = useMemo(() => {
        let data = [...clients];

        if (searchTerm) {
            const lowerTerm = searchTerm.toLowerCase();
            data = data.filter(c => 
                Object.values(c).some(val => 
                    String(val).toLowerCase().includes(lowerTerm)
                )
            );
        }

        if (statusFilter !== 'all') {
            data = data.filter(c => c['Статус сделки'] === statusFilter);
        }

        if (debtFilter) {
             data = data.filter(c => (Number(c['Долг']) || 0) > 0);
        }

        if (warehouseFilter) {
             const lowerW = warehouseFilter.toLowerCase();
             data = data.filter(c => (c['Склад хранения'] || '').toLowerCase().includes(lowerW));
        }

        if (sortConfig) {
            data.sort((a, b) => {
                const aVal = a[sortConfig.key];
                const bVal = b[sortConfig.key];
                if (aVal < bVal) return sortConfig.direction === 'ascending' ? -1 : 1;
                if (aVal > bVal) return sortConfig.direction === 'ascending' ? 1 : -1;
                return 0;
            });
        }
        return data;
    }, [clients, searchTerm, sortConfig, statusFilter, debtFilter, warehouseFilter]);

    const handleRowClick = (client: Client) => {
        setSelectedClient(client);
        setIsModalOpen(true);
    };

    const handleSaveClient = async (updatedClient: Partial<Client>) => {
        try {
            await api.updateClient(updatedClient);
            showToast('Клиент успешно обновлен', 'success');
            await refreshData();
        } catch (e: any) {
            showToast(`Ошибка обновления: ${e.message}`, 'error');
        }
    };

    const handleDeleteClient = async (clientId: string) => {
        try {
            await api.deleteClient(clientId);
            setIsModalOpen(false);
            showToast('Клиент удален', 'success');
            await refreshData();
        } catch (e: any) {
             showToast(`Ошибка удаления: ${e.message}`, 'error');
        }
    };

    const handleBulkDelete = async () => {
        if (!window.confirm(`Вы уверены, что хотите удалить ${selectedClientIds.size} клиентов?`)) return;
        try {
            await api.bulkDeleteClients(Array.from(selectedClientIds));
            setSelectedClientIds(new Set());
            showToast('Клиенты удалены', 'success');
            await refreshData();
        } catch (e: any) {
            showToast(`Ошибка массового удаления: ${e.message}`, 'error');
        }
    };

    const handleSendMessage = async (client: Client, message: string) => {
         try {
             const result = await api.sendMessage(client['Chat ID'] as string, message);
             showToast(result.message, result.success ? 'success' : 'error');
         } catch (e: any) {
             showToast(e.message, 'error');
         }
    };

    const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.checked) {
            setSelectedClientIds(new Set(filteredClients.map(c => c.id)));
        } else {
            setSelectedClientIds(new Set());
        }
    };

    const handleSelectRow = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        const newSet = new Set(selectedClientIds);
        if (newSet.has(id)) newSet.delete(id);
        else newSet.add(id);
        setSelectedClientIds(newSet);
    };

    const handleSaveView = (name: string) => {
        const newView: SavedView = {
            id: Date.now().toString(),
            name,
            filters: { status: statusFilter, warehouse: warehouseFilter, debt: debtFilter },
            sortConfig
        };
        onSaveViews([...savedViews, newView]);
        showToast('Вид сохранен', 'success');
    };

    const applyView = (view: SavedView) => {
        setStatusFilter(view.filters.status);
        setWarehouseFilter(view.filters.warehouse);
        setDebtFilter(view.filters.debt);
        setSortConfig(view.sortConfig);
    };

    const deleteView = (id: string, e: React.MouseEvent) => {
        e.stopPropagation();
        onSaveViews(savedViews.filter(v => v.id !== id));
    };

    // Columns to show in the table (simplified)
    const tableColumns = ['Имя клиента', 'Телефон', 'Номер Авто', 'Окончание', 'Склад хранения', 'Статус сделки', 'Долг'];

    return (
        <div className="p-4 sm:p-6 lg:p-8 space-y-4 h-full flex flex-col">
            {toast && <Toast message={toast.message} type={toast.type} onClose={() => setToast(null)} />}

            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                 <div className="relative w-full sm:w-72">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <SearchIcon className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white dark:bg-gray-800 dark:border-gray-600 dark:text-white placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 focus:ring-primary-500 focus:border-primary-500 sm:text-sm"
                        placeholder="Поиск клиентов..."
                        value={searchTerm}
                        onChange={e => setSearchTerm(e.target.value)}
                    />
                </div>

                <div className="flex items-center gap-2 w-full sm:w-auto overflow-x-auto">
                    <button onClick={refreshData} className="p-2 rounded-md hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400" title="Обновить">
                        <SyncIcon className="h-5 w-5"/>
                    </button>
                    <button 
                        onClick={() => setShowFilters(!showFilters)}
                        className={`p-2 rounded-md border ${showFilters || debtFilter || statusFilter !== 'all' ? 'bg-primary-50 border-primary-200 text-primary-600 dark:bg-primary-900/30 dark:border-primary-800' : 'border-gray-300 dark:border-gray-600 text-gray-600 dark:text-gray-300'}`}
                    >
                         <FilterIcon className="h-5 w-5"/>
                    </button>
                    <div className="relative group">
                        <button className="p-2 rounded-md hover:bg-gray-100 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400">
                             <BookmarkIcon className="h-5 w-5"/>
                        </button>
                         {/* Saved Views Dropdown */}
                        <div className="absolute right-0 mt-2 w-56 rounded-md shadow-lg bg-white dark:bg-gray-800 ring-1 ring-black ring-opacity-5 hidden group-hover:block z-50">
                            <div className="py-1" role="menu">
                                <div className="px-4 py-2 border-b border-gray-100 dark:border-gray-700">
                                    <button 
                                        onClick={() => {
                                            const name = prompt('Название вида:');
                                            if (name) handleSaveView(name);
                                        }}
                                        className="text-xs font-bold text-primary-600 hover:text-primary-700 dark:text-primary-400"
                                    >
                                        + Сохранить текущий
                                    </button>
                                </div>
                                {savedViews.length === 0 && <p className="px-4 py-2 text-sm text-gray-500">Нет сохраненных видов</p>}
                                {savedViews.map(view => (
                                    <div key={view.id} onClick={() => applyView(view)} className="flex justify-between items-center px-4 py-2 text-sm text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 cursor-pointer">
                                        <span>{view.name}</span>
                                        <button onClick={(e) => deleteView(view.id, e)} className="text-gray-400 hover:text-red-500"><XMarkIcon className="h-4 w-4"/></button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                    <Link to="/add-client" className="ml-2">
                        <Button>
                            <PlusIcon className="mr-1 -ml-1"/> Добавить
                        </Button>
                    </Link>
                </div>
            </div>

            {/* Filter Bar */}
            {(showFilters || debtFilter || statusFilter !== 'all') && (
                <div className="p-4 bg-gray-50 dark:bg-gray-800 rounded-md border border-gray-200 dark:border-gray-700 grid grid-cols-1 sm:grid-cols-4 gap-4 animate-in slide-in-from-top-2">
                     <div>
                        <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Статус</label>
                        <select 
                            value={statusFilter} 
                            onChange={e => setStatusFilter(e.target.value)} 
                            className="block w-full pl-3 pr-10 py-1.5 text-sm border-gray-300 focus:outline-none focus:ring-primary-500 focus:border-primary-500 rounded-md dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                        >
                            <option value="all">Все</option>
                            <option value="На складе">На складе</option>
                            <option value="Завершено">Завершено</option>
                            <option value="Без оплаты">Без оплаты</option>
                            <option value="Частичная оплата">Частичная оплата</option>
                        </select>
                     </div>
                     <div>
                        <label className="block text-xs font-medium text-gray-500 uppercase mb-1">Склад</label>
                         <input 
                            type="text" 
                            value={warehouseFilter}
                            onChange={e => setWarehouseFilter(e.target.value)}
                            placeholder="Например: A-1"
                            className="block w-full pl-3 pr-3 py-1.5 text-sm border-gray-300 focus:outline-none focus:ring-primary-500 focus:border-primary-500 rounded-md dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                         />
                     </div>
                     <div className="flex items-end pb-2">
                        <label className="flex items-center space-x-2 cursor-pointer">
                            <input type="checkbox" checked={debtFilter} onChange={e => setDebtFilter(e.target.checked)} className="rounded text-primary-600 focus:ring-primary-500 h-4 w-4 border-gray-300 dark:border-gray-600 dark:bg-gray-700" />
                            <span className="text-sm font-medium text-gray-700 dark:text-gray-300">Только должники</span>
                        </label>
                     </div>
                     <div className="flex items-end justify-end">
                         <button onClick={() => { setStatusFilter('all'); setWarehouseFilter(''); setDebtFilter(false); }} className="text-xs text-gray-500 underline hover:text-gray-800 dark:hover:text-gray-200">
                             Сбросить все
                         </button>
                     </div>
                </div>
            )}

            {/* Bulk Actions */}
            {selectedClientIds.size > 0 && (
                <div className="bg-primary-50 dark:bg-primary-900/40 border border-primary-200 dark:border-primary-800 p-2 rounded-md flex items-center justify-between animate-in fade-in">
                    <span className="text-sm font-medium text-primary-800 dark:text-primary-200 ml-2">Выбрано: {selectedClientIds.size}</span>
                    <div className="space-x-2">
                        <Button size="sm" variant="danger" onClick={handleBulkDelete}><DeleteIcon/> Удалить</Button>
                    </div>
                </div>
            )}

            <Card className="flex-1 overflow-hidden flex flex-col !p-0" noOverflow>
                <div className="overflow-x-auto flex-1">
                    <table className="min-w-full divide-y divide-gray-200 dark:divide-gray-700">
                        <thead className="bg-gray-50 dark:bg-gray-800 sticky top-0 z-10">
                            <tr>
                                <th scope="col" className="px-6 py-3 text-left">
                                    <input type="checkbox" onChange={handleSelectAll} className="rounded border-gray-300 text-primary-600 focus:ring-primary-500 h-4 w-4" />
                                </th>
                                {tableColumns.map(col => (
                                    <th 
                                        key={col} 
                                        scope="col" 
                                        className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-700"
                                        onClick={() => handleSort(col)}
                                    >
                                        <div className="flex items-center space-x-1">
                                            <span>{col}</span>
                                            {sortConfig?.key === col && (
                                                <span>{sortConfig.direction === 'ascending' ? '↑' : '↓'}</span>
                                            )}
                                        </div>
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody className="bg-white dark:bg-gray-900 divide-y divide-gray-200 dark:divide-gray-800">
                            {filteredClients.map(client => (
                                <tr 
                                    key={client.id} 
                                    onClick={() => handleRowClick(client)} 
                                    className={`hover:bg-gray-50 dark:hover:bg-gray-800 cursor-pointer transition-colors ${selectedClientIds.has(client.id) ? 'bg-primary-50 dark:bg-primary-900/20' : ''}`}
                                >
                                    <td className="px-6 py-4 whitespace-nowrap" onClick={e => e.stopPropagation()}>
                                        <input 
                                            type="checkbox" 
                                            checked={selectedClientIds.has(client.id)} 
                                            onChange={(e) => {}} // handled by parent onClick wrapper via propagation stop, but explicitly:
                                            onClick={(e) => handleSelectRow(client.id, e)}
                                            className="rounded border-gray-300 text-primary-600 focus:ring-primary-500 h-4 w-4" 
                                        />
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <div className="text-sm font-medium text-gray-900 dark:text-white">{client['Имя клиента']}</div>
                                        <div className="text-xs text-gray-500 dark:text-gray-400">ID: {client['Chat ID'] || '-'}</div>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">{client['Телефон']}</td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                         <span className="px-2 inline-flex text-xs leading-5 font-semibold rounded-full bg-gray-100 dark:bg-gray-800 text-gray-800 dark:text-gray-200 font-mono">
                                            {client['Номер Авто']}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                                        {formatDateForDisplay(client['Окончание'])}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500 dark:text-gray-400">
                                        {client['Склад хранения']} / {client['Ячейка']}
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap">
                                        <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                                            client['Статус сделки'] === 'На складе' ? 'bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200' : 
                                            client['Статус сделки'] === 'Без оплаты' ? 'bg-red-100 text-red-800 dark:bg-red-900 dark:text-red-200' : 
                                            'bg-gray-100 text-gray-800 dark:bg-gray-700 dark:text-gray-300'
                                        }`}>
                                            {client['Статус сделки']}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 whitespace-nowrap text-sm">
                                         {Number(client['Долг']) > 0 ? (
                                             <span className="text-red-600 font-bold">{new Intl.NumberFormat('ru-RU').format(client['Долг'])} ₽</span>
                                         ) : (
                                             <span className="text-green-600">0 ₽</span>
                                         )}
                                    </td>
                                </tr>
                            ))}
                            {filteredClients.length === 0 && (
                                <tr>
                                    <td colSpan={tableColumns.length + 1} className="px-6 py-4 text-center text-gray-500 dark:text-gray-400">
                                        Клиенты не найдены
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </Card>

            {selectedClient && (
                <ClientDetailModal
                    isOpen={isModalOpen}
                    onClose={() => setIsModalOpen(false)}
                    client={selectedClient}
                    headers={headers}
                    templates={templates}
                    onSave={handleSaveClient}
                    onDelete={handleDeleteClient}
                    onSendMessage={handleSendMessage}
                    refreshData={refreshData}
                    showToast={showToast}
                />
            )}
        </div>
    );
};

import React, { useState, useEffect, useCallback } from 'react';
import { HashRouter, Routes, Route, Link, useLocation, Navigate } from 'react-router-dom';
import { Dashboard } from './components/Dashboard';
import { ClientsView } from './components/ClientsView';
import { Settings } from './components/Settings';
import { AddClient } from './components/AddClient';
import { UserRole, Client, MessageTemplate, Settings as SettingsType, Master, SavedView } from './types';
import { api, getClientHeaders } from './services/api';
import { ThemeSwitcher } from './components/ui/ThemeSwitcher';
import { ToastContainer, ToastMessage } from './components/ui/Toast';

const getInitialSettings = (): SettingsType => {
    const data = localStorage.getItem('crm_settings');
    const defaults: SettingsType = { adminIds: '', managerIds: '', googleSheetId: '', sheetName: 'WebBase' };
    try {
        if (data) {
            return { ...defaults, ...JSON.parse(data) };
        }
    } catch (e) {
        console.error("Could not parse settings from localStorage", e);
    }
    return defaults;
};


